    latest_ts = 0
    for entry in reversed(session.journal):
        if not isinstance(entry, dict):
            continue
        if str(entry.get("sessionId", "")).strip() != session_id:
            continue
        op = str(entry.get("op", "")).strip()
        if op not in target_ops:
            continue
        ts = int(entry.get("timestamp", 0) or 0)
